from dataclasses import dataclass, field
from datetime import datetime
from enum import Enum

class GateStatus(str, Enum):
    NOT_RUN   = "not_run"
    PASSED    = "passed"
    FAILED    = "failed"
    SKIPPED   = "skipped"  # gate not applicable for this change type

@dataclass
class PromotionRecord:
    model_id: str
    from_version: str
    to_version: str
    started_at: datetime
    gates: dict[str, GateStatus] = field(default_factory=dict)
    failure_reason: str = ""
    completed_at: datetime | None = None
    rolled_back: bool = False

    def current_gate(self) -> str | None:
        gate_order = ["unit", "staging", "canary", "production"]
        for gate in gate_order:
            status = self.gates.get(gate, GateStatus.NOT_RUN)
            if status == GateStatus.NOT_RUN:
                return gate
            if status == GateStatus.FAILED:
                return gate
        return None  # all gates passed

    def is_promotable(self) -> bool:
        """True if all gates have passed or been skipped."""
        for status in self.gates.values():
            if status == GateStatus.FAILED:
                return False
            if status == GateStatus.NOT_RUN:
                return False
        return True

    def restart_after_fix(self) -> "PromotionRecord":
        """Creates a new promotion record; all gates reset to NOT_RUN."""
        return PromotionRecord(
            model_id=self.model_id,
            from_version=self.from_version,
            to_version=self.to_version,
            started_at=datetime.utcnow(),
            gates={},  # all gates start over
        )

from dataclasses import dataclass, field
from enum import Enum

class GoldenPromptCategory(str, Enum):
    CORE_TASK        = "core_task"       # the primary application use case
    EDGE_CASE        = "edge_case"       # boundary inputs that used to cause errors
    SAFETY_BOUNDARY  = "safety_boundary" # prompts near refusal thresholds
    STRUCTURED_OUTPUT = "structured_output" # prompts requiring JSON/schema output
    TOOL_USE         = "tool_use"        # prompts that invoke tool calls

@dataclass
class GoldenPromptEntry:
    prompt_id: str
    category: GoldenPromptCategory
    system_prompt: str
    user_message: str
    expected_stop_reason: str        # "end_turn" | "tool_use" | "max_tokens"
    output_schema: dict | None       # JSON schema for structured outputs; None for free text
    min_output_length: int = 0
    max_output_length: int | None = None
    must_contain: list[str] = field(default_factory=list)   # substrings that must appear
    must_not_contain: list[str] = field(default_factory=list)  # substrings that must not appear

    def validate_response(self, content: str, stop_reason: str) -> list[str]:
        failures = []
        if stop_reason != self.expected_stop_reason:
            failures.append(
                f"stop_reason={stop_reason!r}, expected {self.expected_stop_reason!r}"
            )
        if len(content) < self.min_output_length:
            failures.append(
                f"output length {len(content)} below minimum {self.min_output_length}"
            )
        if self.max_output_length and len(content) > self.max_output_length:
            failures.append(
                f"output length {len(content)} above maximum {self.max_output_length}"
            )
        for phrase in self.must_contain:
            if phrase.lower() not in content.lower():
                failures.append(f"required phrase not found: {phrase!r}")
        for phrase in self.must_not_contain:
            if phrase.lower() in content.lower():
                failures.append(f"prohibited phrase found: {phrase!r}")
        return failures
